#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long maxPairs = (long long)(N-1)*(N-2)/2; // C(N-1,2)
        if(K > maxPairs){
            printf("-1\n");
            continue;
        }
        long long need = maxPairs - K; // number of leaf‑leaf edges to add
        int M = (N-1) + need;
        printf("%d\n", M);
        // star edges
        for(int i=2;i<=N;i++) printf("1 %d\n", i);
        // add leaf edges
        for(int i=2;i<=N && need>0;i++){
            for(int j=i+1;j<=N && need>0;j++){
                printf("%d %d\n", i, j);
                need--;
            }
        }
    }
    return 0;
}

