import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long K = fs.nextLong();
            long maxPairs = 1L * (N - 1) * (N - 2) / 2; // C(N-1,2)
            if (K > maxPairs) {
                out.append("-1\n");
                continue;
            }
            long need = maxPairs - K; // leaf‑leaf edges to add
            int M = (N - 1) + (int) need;
            out.append(M).append('\n');
            // star edges
            for (int i = 2; i <= N; i++) {
                out.append(1).append(' ').append(i).append('\n');
            }
            // leaf edges
            outer:
            for (int i = 2; i <= N; i++) {
                for (int j = i + 1; j <= N; j++) {
                    if (need == 0) break outer;
                    out.append(i).append(' ').append(j).append('\n');
                    need--;
                }
            }
        }
        System.out.print(out.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            if (c == -1) return "";
            do { sb.append((char) c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

