#!/usr/bin/env python3
import sys

def solve():
    it = iter(sys.stdin.read().strip().split())
    try:
        T = int(next(it))
    except StopIteration:
        return
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        max_pairs = (N-1)*(N-2)//2  # C(N-1,2)
        if K > max_pairs:
            out_lines.append('-1')
            continue
        need = max_pairs - K  # leaf‑leaf edges to add
        M = (N-1) + need
        out_lines.append(str(M))
        # star edges
        for i in range(2, N+1):
            out_lines.append(f'1 {i}')
        # leaf edges
        for i in range(2, N+1):
            if need == 0:
                break
            for j in range(i+1, N+1):
                if need == 0:
                    break
                out_lines.append(f'{i} {j}')
                need -= 1
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

